    def _fib_doubling(k):
        if k == 0:
            return (0, 1)
        half_a, half_b = _fib_doubling(k >> 1)
        c = half_a * (2 * half_b - half_a)
        d = half_a * half_a + half_b * half_b
        if k & 1:
            return (d, c + d)
