def fibonacci(n):
    if n < 0:
        raise ValueError("Input must be a non-negative integer")
    if n <= 1:
        return n

    a, b = 0, 1
    high_bit = n.bit_length() - 1

    for i in range(high_bit - 1, -1, -1):
        t = b + b
        c = a * (t - a)
        d = a * a + b * b
        if (n >> i) & 1:
            a = d
            b = c + d
        else:
            a = c
            b = d

    return a
